package ua.university.sms.service;
import org.junit.jupiter.api.*;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.boot.test.context.SpringBootTest;import ua.university.sms.model.dto.EnrollmentDtos.*;import static org.junit.jupiter.api.Assertions.*;
@SpringBootTest class EnrollmentServiceTest{@Autowired EnrollmentService service;@Test void averageByCourseWorks(){assertNotNull(service.averageByCourse(1L));}@Test void paymentCanBeChanged(){var r=service.setPaid(2L,new PaymentRequest(true));assertTrue(r.paid());}@Test void gradeCanBeChanged(){var r=service.setGrade(4L,new GradeRequest(75.0));assertEquals(75.0,r.grade());}@Test void rejectsDuplicateEnrollment(){assertThrows(IllegalStateException.class,()->service.create(new Request(1L,1L,true,90.0)));}@Test void rejectsUnknownStudent(){assertThrows(RuntimeException.class,()->service.create(new Request(999L,1L,true,90.0)));}}
